output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?games) AS ?total_games) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?series wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840 ; wdt:P585 ?dateTime ; wdt:P433 ?games .
  FILTER(YEAR(?dateTime) = ?year)
}

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT (SUM(?games) AS ?total_games)
WHERE {
  VALUES ?year { 1977 1978 2008 2009 }
  ?series 
    wdt:P710 wd:Q334634 ; 
    wdt:P710 wd:Q650840 ;
    wdt:P585 ?dateTime ;
    wdt:P433 ?games .

  FILTER(YEAR(?dateTime) = ?year)
}
